class Commit {
  final PlatformInt64 timestamp;
  final String authorUsername;
  final String authorEmail;
  final String reference;
  final String commitMessage;
  final int additions;
  final int deletions;
  final bool unpulled;
  final bool unpushed;
  final List<String> tags;

  const Commit({
    required this.timestamp,
    required this.authorUsername,
    required this.authorEmail,
    required this.reference,
    required this.commitMessage,
    required this.additions,
    required this.deletions,
    required this.unpulled,
    required this.unpushed,
    required this.tags,
  });

  @override
  int get hashCode =>
      timestamp.hashCode ^
      authorUsername.hashCode ^
      authorEmail.hashCode ^
      reference.hashCode ^
      commitMessage.hashCode ^
      additions.hashCode ^
      deletions.hashCode ^
      unpulled.hashCode ^
      unpushed.hashCode ^
      tags.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is Commit &&
          runtimeType == other.runtimeType &&
          timestamp == other.timestamp &&
          authorUsername == other.authorUsername &&
          authorEmail == other.authorEmail &&
          reference == other.reference &&
          commitMessage == other.commitMessage &&
          additions == other.additions &&
          deletions == other.deletions &&
          unpulled == other.unpulled &&
          unpushed == other.unpushed &&
          tags == other.tags;
}

